import { useEffect, useState } from "react";
import axios from "axios";
import {
  Box, Typography, Button,
  Table, TableHead, TableRow,
  TableCell, TableBody, Paper,
  FormControl, InputLabel, Select, MenuItem,
  Dialog, DialogTitle, DialogContent,
  Snackbar, Alert, Chip
} from "@mui/material";

import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

import Header from "../components/header";
import AdminSidebar from "../components/sidebar";

export default function AdminSeating() {

  const [departments, setDepartments] = useState([]);
  const [students, setStudents] = useState([]);
  const [staffList, setStaffList] = useState([]);
  const [rooms, setRooms] = useState([]);

  const [selectedDepts, setSelectedDepts] = useState([]);
  const [selectedClasses, setSelectedClasses] = useState([]);
  const [selectedStaff, setSelectedStaff] = useState("");
  const [selectedRooms, setSelectedRooms] = useState([]);

  const [seating, setSeating] = useState([]);
  const [overflow, setOverflow] = useState([]);

  const [openVisual, setOpenVisual] = useState(false);
  const [notify, setNotify] = useState(false);

  /* ================= FETCH DB DATA ================= */
  useEffect(() => {
    axios.get("http://127.0.0.1:5000/api/students")
      .then(res => setStudents(res.data.students || []));

    axios.get("http://127.0.0.1:5000/api/students/departments")
      .then(res => setDepartments(res.data.departments || []));

    axios.get("http://127.0.0.1:5000/api/staff")
      .then(res => setStaffList(res.data.staff || []));

    axios.get("http://127.0.0.1:5000/api/rooms")
      .then(res => setRooms(res.data.rooms || []));
  }, []);

  /* ================= GET CLASSES FOR SELECTED DEPT ================= */
  const getClassesForDept = (dept) => {
    const deptStudents = students.filter(s => s.department_name === dept);
    const semesters = [...new Set(deptStudents.map(s => s.semester))].sort();
    
    const classMap = {
      1: "I MA",
      2: "II MA",
      3: "III MA",
      4: "IV MA",
      5: "V MA",
      6: "VI MA"
    };
    
    return semesters.map(sem => ({
      value: sem,
      label: classMap[sem] || `Sem ${sem}`
    }));
  };

  /* ================= GET STUDENT RANGE ================= */
  const getStudentRange = (dept, cls) => {
    const filtered = students
      .filter(s => s.department_name === dept && s.semester === cls)
      .sort((a, b) => a.register_no.localeCompare(b.register_no));
    
    if (filtered.length === 0) return null;
    
    return {
      start: filtered[0].register_no,
      end: filtered[filtered.length - 1].register_no,
      count: filtered.length
    };
  };

  /* ================= CALCULATE TOTAL CAPACITY ================= */
  const getTotalCapacity = () => {
    return selectedRooms.reduce((total, roomNo) => {
      const room = rooms.find(r => r.room_no === roomNo);
      return total + (room?.capacity || 0);
    }, 0);
  };

  /* ================= GENERATE SEATING ================= */
  const generateSeating = () => {
    if (selectedDepts.length === 0 || selectedClasses.length === 0 || 
        selectedStaff === "" || selectedRooms.length === 0) {
      alert("Select Department, Class, Invigilator & Room(s)");
      return;
    }

    // Get all students for selected departments and classes
    let filteredStudents = students.filter(s =>
      selectedDepts.includes(s.department_name) && 
      selectedClasses.includes(s.semester)
    );

    // Sort by register number
    filteredStudents.sort((a, b) => a.register_no.localeCompare(b.register_no));

    const totalCapacity = getTotalCapacity();
    
    // First priority: seat as many as possible
    const seated = filteredStudents.slice(0, totalCapacity);
    const remaining = filteredStudents.slice(totalCapacity);

    setSeating(seated);
    setOverflow(remaining);

    if (remaining.length > 0) setNotify(true);
  };

  /* ================= GET ROOM STUDENTS ================= */
  const getRoomStudents = (roomNo) => {
    const room = rooms.find(r => r.room_no === roomNo);
    const roomCapacity = room?.capacity || 0;
    
    // Calculate starting index for this room
    let startIndex = 0;
    for (const r of selectedRooms) {
      if (r === roomNo) break;
      const rObj = rooms.find(room => room.room_no === r);
      startIndex += (rObj?.capacity || 0);
    }
    
    return seating.slice(startIndex, startIndex + roomCapacity);
  };

  /* ================= EXPORT PDF ================= */
  const exportPDF = () => {
    const doc = new jsPDF();

    doc.text("Exam Seating Arrangement", 14, 15);
    doc.setFontSize(10);

    doc.text(`Rooms : ${selectedRooms.join(", ")}`, 14, 25);
    doc.text(`Invigilator : ${selectedStaff}`, 14, 31);
    doc.text(`Departments : ${selectedDepts.join(", ")}`, 14, 37);
    doc.text(`Classes : ${selectedClasses.join(", ")}`, 14, 43);
    doc.text(`Seated : ${seating.length}`, 14, 49);
    doc.text(`Remaining : ${overflow.length}`, 14, 55);

    autoTable(doc, {
      startY: 60,
      head: [["Reg No", "Name", "Department", "Semester"]],
      body: seating.map(s => [
        s.register_no,
        s.student_name,
        s.department_name,
        s.semester
      ])
    });

    doc.save("seating-arrangement.pdf");
  };

  /* ================= HANDLE DEPARTMENT CHANGE ================= */
  const handleDeptChange = (deptValues) => {
    setSelectedDepts(deptValues);
    setSelectedClasses([]);
    setSeating([]);
    setOverflow([]);
  };

  /* ================= HANDLE CLASS CHANGE ================= */
  const handleClassChange = (classValues) => {
    setSelectedClasses(classValues);
    setSeating([]);
    setOverflow([]);
  };

  return (
    <>
      <Header />
      <Box sx={{ display: "flex" }}>
        <AdminSidebar />

        <Box sx={{ p: 3, flexGrow: 1 }}>
          <Typography variant="h6" mb={2}>
            Seating Arrangement
          </Typography>

          {/* ================= DEPARTMENT SELECT ================= */}
          <Box sx={{ mb: 3 }}>
            <FormControl size="small" sx={{ minWidth: 280, mr: 2 }}>
              <InputLabel>Department</InputLabel>
              <Select
                multiple
                value={selectedDepts}
                onChange={(e) => handleDeptChange(e.target.value)}
                renderValue={(selected) => (
                  <Box sx={{ display: "flex", flexWrap: "wrap", gap: 0.5 }}>
                    {selected.map((value) => (
                      <Chip key={value} label={value} size="small" />
                    ))}
                  </Box>
                )}
              >
                {departments.map(d => (
                  <MenuItem key={d} value={d}>{d}</MenuItem>
                ))}
              </Select>
            </FormControl>
          </Box>

          {/* ================= CLASS BUTTONS (Show when dept selected) ================= */}
          {selectedDepts.length > 0 && (
            <Box sx={{ mb: 3 }}>
              <Typography variant="subtitle2" mb={1} fontWeight="bold">
                Select Class:
              </Typography>
              <Box sx={{ display: "flex", gap: 1, flexWrap: "wrap" }}>
                {selectedDepts.map(dept => {
                  const classes = getClassesForDept(dept);
                  return classes.map(cls => (
                    <Button
                      key={`${dept}-${cls.value}`}
                      variant={selectedClasses.includes(cls.value) ? "contained" : "outlined"}
                      onClick={() => {
                        const newClasses = selectedClasses.includes(cls.value)
                          ? selectedClasses.filter(c => c !== cls.value)
                          : [...selectedClasses, cls.value];
                        handleClassChange(newClasses);
                      }}
                      sx={{ minWidth: 100 }}
                    >
                      {cls.label}
                    </Button>
                  ));
                })}
              </Box>
              
              {/* Show student range for selected classes */}
              {selectedClasses.length > 0 && selectedDepts.map(dept => {
                const deptClasses = selectedClasses.filter(c => {
                  const deptStudents = students.filter(s => s.department_name === dept);
                  return deptStudents.some(s => s.semester === c);
                });
                
                return deptClasses.map(cls => {
                  const range = getStudentRange(dept, cls);
                  if (!range) return null;
                  
                  const clsLabel = getClassesForDept(dept).find(c => c.value === cls)?.label;
                  
                  return (
                    <Typography key={`${dept}-${cls}-range`} variant="body2" sx={{ mt: 1, color: "#666" }}>
                      <Chip label={clsLabel} size="small" sx={{ mr: 1 }} />
                      {range.start} - {range.end} ({range.count} students)
                    </Typography>
                  );
                });
              })}
            </Box>
          )}

          {/* ================= INVIGILATOR & ROOM SELECT (Show when class selected) ================= */}
          {selectedClasses.length > 0 && (
            <Box sx={{ mb: 3, display: "flex", gap: 2, flexWrap: "wrap" }}>
              <FormControl size="small" sx={{ minWidth: 200 }}>
                <InputLabel>Invigilator</InputLabel>
                <Select
                  value={selectedStaff}
                  onChange={(e) => setSelectedStaff(e.target.value)}
                >
                  {staffList.map(s => (
                    <MenuItem key={s.id} value={s.staff_name}>
                      {s.staff_name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>

              <FormControl size="small" sx={{ minWidth: 250 }}>
                <InputLabel>Hall(s)</InputLabel>
                <Select
                  multiple
                  value={selectedRooms}
                  onChange={(e) => {
                    setSelectedRooms(e.target.value);
                    setSeating([]);
                    setOverflow([]);
                  }}
                  renderValue={(selected) => (
                    <Box sx={{ display: "flex", flexWrap: "wrap", gap: 0.5 }}>
                      {selected.map((value) => (
                        <Chip key={value} label={value} size="small" />
                      ))}
                    </Box>
                  )}
                >
                  {rooms.map(r => (
                    <MenuItem key={r.id} value={r.room_no}>
                      {r.room_no} (Capacity: {r.capacity})
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>

              <Button variant="contained" onClick={generateSeating} sx={{ minWidth: 120 }}>
                Generate
              </Button>
            </Box>
          )}

          {/* ================= ROOM CAPACITY INFO ================= */}
          {selectedRooms.length > 0 && (
            <Typography variant="body2" sx={{ mb: 2, color: "#1976d2" }}>
              Total Capacity: {getTotalCapacity()} seats
              {selectedClasses.length > 0 && (
                <> | Selected Students: {
                  students.filter(s => 
                    selectedDepts.includes(s.department_name) && 
                    selectedClasses.includes(s.semester)
                  ).length
                }</>
              )}
            </Typography>
          )}

          {/* ================= COUNT ================= */}
          {seating.length > 0 && (
            <Typography mb={1} fontWeight="600">
              Seated : {seating.length} | Remaining (Not Allocated) : {overflow.length}
            </Typography>
          )}

          {/* ================= SEATING TABLE ================= */}
          {seating.length > 0 && (
            <Paper>
              <Table>
                <TableHead>
                  <TableRow>
                    <TableCell>S.No</TableCell>
                    <TableCell>Register No</TableCell>
                    <TableCell>Name</TableCell>
                    <TableCell>Department</TableCell>
                    <TableCell>Semester</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {seating.map((s, i) => (
                    <TableRow key={s.id || i}>
                      <TableCell>{i + 1}</TableCell>
                      <TableCell>{s.register_no}</TableCell>
                      <TableCell>{s.student_name}</TableCell>
                      <TableCell>{s.department_name}</TableCell>
                      <TableCell>{s.semester}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </Paper>
          )}

          {/* ================= ACTION BUTTONS ================= */}
          {seating.length > 0 && (
            <Box sx={{ mt: 2, display: "flex", gap: 2 }}>
              <Button variant="outlined" onClick={() => setOpenVisual(true)}>
                VISUALS 👁
              </Button>
              <Button variant="outlined" color="success" onClick={exportPDF}>
                Export PDF
              </Button>
            </Box>
          )}
        </Box>
      </Box>

      {/* ================= VISUAL DIALOG ================= */}
      <Dialog open={openVisual} onClose={() => setOpenVisual(false)} maxWidth="lg" fullWidth>
        <DialogTitle>
          Seating Visual - {selectedRooms.join(", ")}
        </DialogTitle>
        <DialogContent>
          {selectedRooms.map(roomNo => {
            const room = rooms.find(r => r.room_no === roomNo);
            const roomStudents = getRoomStudents(roomNo);
            
            return (
              <Box key={roomNo} sx={{ mb: 3 }}>
                <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1 }}>
                  Hall {roomNo} (Capacity: {room?.capacity || 0})
                </Typography>
                <Box sx={{ display: "grid", gridTemplateColumns: "repeat(10, 1fr)", gap: 0.5 }}>
                  {[...Array(room?.capacity || 0)].map((_, i) => (
                    <Box
                      key={i}
                      sx={{
                        border: "1px solid #333",
                        height: 30,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        bgcolor: roomStudents[i] ? "#c8e6c9" : "#ffcdd2",
                        fontSize: "10px",
                        fontWeight: "bold"
                      }}
                      title={roomStudents[i] ? `${roomStudents[i].register_no} - ${roomStudents[i].student_name}` : `Seat ${i + 1}`}
                    >
                      {roomStudents[i] ? "×" : i + 1}
                    </Box>
                  ))}
                </Box>
                <Typography variant="caption" sx={{ mt: 0.5, display: "block" }}>
                  Occupied: {roomStudents.length} | Available: {(room?.capacity || 0) - roomStudents.length}
                </Typography>
              </Box>
            );
          })}
          
          <Box sx={{ mt: 2, display: "flex", gap: 3 }}>
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              <Box sx={{ width: 20, height: 20, bgcolor: "#c8e6c9", border: "1px solid #333", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "12px" }}>×</Box>
              <Typography variant="body2">Occupied ({seating.length})</Typography>
            </Box>
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              <Box sx={{ width: 20, height: 20, bgcolor: "#ffcdd2", border: "1px solid #333", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "12px" }}>1</Box>
              <Typography variant="body2">Available ({getTotalCapacity() - seating.length})</Typography>
            </Box>
          </Box>
        </DialogContent>
      </Dialog>

      {/* ================= WARNING ================= */}
      <Snackbar open={notify} autoHideDuration={5000} onClose={() => setNotify(false)}>
        <Alert severity="warning">
          ⚠ {overflow.length} students not allocated – add more rooms
        </Alert>
      </Snackbar>
    </>
  );
}
